import openpyxl

wb = openpyxl.load_workbook('/sessions/keen-quirky-wright/mnt/uploads/电算票据应对.xlsx')

def get_fill_color(cell):
    fill = cell.fill
    if fill and fill.fgColor:
        color = fill.fgColor
        if color.type == 'rgb':
            return color.rgb
        elif color.type == 'theme':
            return f"theme:{color.theme}"
    return None

def is_pink(cell):
    color = get_fill_color(cell)
    if color is None:
        return False
    # Pink colors typically have high R, medium-high G, high B but lower than R
    # Common pink: FFFF99CC, FFFFB6C1, FFFFC0CB, FF FFB3BA
    # Also check for light pink / salmon
    if color and len(color) == 8:
        r = int(color[2:4], 16)
        g = int(color[4:6], 16)
        b = int(color[6:8], 16)
        # Pink-ish: high red, lower green, medium-high blue, or typical Excel pink fills
        # Let's just collect all non-white, non-default fills
        if r != 0 or g != 0 or b != 0:
            return True
    return False

# Collect all colored cells
for sheet_name in wb.sheetnames:
    if sheet_name == 'Summary':
        continue
    ws = wb[sheet_name]
    colored = []
    for row in ws.iter_rows():
        for cell in row:
            color = get_fill_color(cell)
            if color and color not in ('00000000', 'FFFFFFFF', 'FF000000'):
                colored.append((cell.coordinate, color, cell.value))
    print(f"\n=== {sheet_name} - Colored cells ===")
    print(f"Total: {len(colored)}")
    for coord, color, val in colored[:20]:
        print(f"  {coord}: color={color}, value={val}")
    if len(colored) > 20:
        print(f"  ... and {len(colored)-20} more")
EOF
