import openpyxl

wb = openpyxl.load_workbook('/sessions/keen-quirky-wright/mnt/uploads/电算票据应对.xlsx')

def get_fill_color(cell):
    fill = cell.fill
    if fill and fill.fgColor:
        color = fill.fgColor
        if color.type == 'rgb':
            return color.rgb
    return None

def is_pink(cell):
    color = get_fill_color(cell)
    return color == 'FFFFC7CE'

# Print all pink cells with context (surrounding rows for field name)
for sheet_name in wb.sheetnames:
    if sheet_name == 'Summary':
        continue
    ws = wb[sheet_name]
    print(f"\n{'='*60}")
    print(f"Sheet: {sheet_name}")
    print(f"{'='*60}")

    # Get header row
    headers = {}
    for cell in ws[1]:
        headers[cell.column] = cell.value

    pink_rows = set()
    for row in ws.iter_rows():
        for cell in row:
            if is_pink(cell):
                pink_rows.add(cell.row)

    for row_num in sorted(pink_rows):
        row_data = {}
        for col_num, header in headers.items():
            cell = ws.cell(row=row_num, column=col_num)
            row_data[header] = cell.value

        # Mark which cell(s) are pink
        pink_cols = []
        for col_num, header in headers.items():
            cell = ws.cell(row=row_num, column=col_num)
            if is_pink(cell):
                pink_cols.append(header)

        print(f"\nRow {row_num} (Pink cols: {pink_cols})")
        for h, v in row_data.items():
            if h:
                print(f"  {h}: {v}")

EOF
