    if cell.value:
        print(f"  Col {cell.column} ({cell.column_letter}): {cell.value}")

print("\nRow 5 full data:")
for cell in ws[5]:
    color = get_fill_color(cell)
    print(f"  Col {cell.column_letter}: value={cell.value!r}, color={color}")

