for row_num in [7, 10]:
    print(f"\nRow {row_num} full data:")
    for cell in ws[row_num]:
        color = get_fill_color(cell)
        if cell.value is not None or color:
            print(f"  Col {cell.column_letter}: value={cell.value!r}, color={color}")

